INSERT INTO "signals" VALUES(106,'BLKB','2026-05-04','news','Blackbaud Makes a Strategic Investment in Student First to Bring Stronger Connected Campus Experience to Higher Education Institutions','Partnership Will Enable Higher Education Customers to Pair Student First''s Future-Ready Student Information System with Blackbaud''s Leading Financial Management and Fundraising Solutions to Unify Back-Office Operations and Power Student Success CHARLESTON, S.C., May 4, 2026 /PRNewswire/ -- Blackbaud (NASDAQ: BLKB), the world''s leading provider of AI-powered solutions for social impact, today announced a strategic investment in Student First, the provider of the most modern, AI-enabled student information system (SIS) designed to simplify administrative workflows and enhance the student experience for higher education institutions.','PRNewsWire','2026-05-06T23:45:57','medium');
