INSERT INTO "signals" VALUES(224,'CAR','2026-05-04','news','Fate Therapeutics Announces Three Presentations at the 2026 ASGCT Annual Meeting Highlighting Off-the-Shelf CAR T-cell Therapy Pipeline for Cancer and Autoimmune Diseases','SAN DIEGO, May 04, 2026 (GLOBE NEWSWIRE) -- Fate Therapeutics, Inc. (NASDAQ: FATE), a clinical-stage biopharmaceutical company dedicated to bringing a transformative pipeline of induced pluripotent stem cell (iPSC)-derived cellular immunotherapies to patients with cancer and autoimmune diseases, today announced that data from its off-the-shelf CAR T-cell programs FT819, FT839, and FT836, will be featured at the American Society of Gene and Cell Therapy (ASGCT) Annual Meeting to be held in Boston, MA, May 11–15, 2026. Fate Therapeutics will present clinical and translational data from the systemic lupus erythematosus (SLE) arm of its ongoing Phase 1 trial evaluating FT819 in Regimen B, where FT819 is added to background maintenance therapy without the use of conditioning chemotherapy to dri','GlobeNewsWire','2026-05-06T23:46:08','medium');
