INSERT INTO "signals" VALUES(270,'CNR','2026-05-04','news','CN Reports April Grain Movement','MONTREAL, May 04, 2026 (GLOBE NEWSWIRE) -- CN (TSX: CNR) (NYSE: CNI) announced today that in April it moved 3.2 million metric tonnes of grain from Western Canada, again setting a new monthly record for grain movement.  That makes eight months of strong performance for this crop year, with seven months being new monthly records.  CN''s strong network performance is enabling a record-setting volume pace as a result of the steady export demand, the available grain and CN''s efficient operations across both export corridors and within Canada and the US.','GlobeNewsWire','2026-05-06T23:46:12','medium');
