INSERT INTO "signals" VALUES(374,'EVTC','2026-05-06','news','EVERTEC Reports First Quarter 2026 Results','SAN JUAN, Puerto Rico--(BUSINESS WIRE)--EVERTEC, Inc. (NYSE: EVTC) (“Evertec” or the “Company”) today announced results for the first quarter ended March 31, 2026. First Quarter 2026 Highlights and Recent Highlights Revenue increased 8% to $247.9 million, approximately 5% on a constant currency basis GAAP Net Income attributable to common shareholders decreased 27% to $23.8 million, and decreased 24% to $0.38 per diluted share Adjusted EBITDA increased 9% to $97.0 million and Adjusted earnings.','Business Wire','2026-05-06T23:47:06','medium');
INSERT INTO "signals" VALUES(375,'EVTC','2026-05-06','8k','EVERTEC, Inc.  (EVTC)  (CIK 0001559865) 8-K','EVTC 2026-05-06','SEC EDGAR','2026-05-06T23:47:06','low');
INSERT INTO "signals" VALUES(377,'EXPO','2026-05-04','news','Exponent: Rising Demand And A Reasonable Valuation Make It A Buy','Exponent is a market leader in scientific and engineering consulting, boasting a 13-year dividend growth streak and a fortress balance sheet. EXPO''s fiscal 2026 outlook signals rising top and bottom lines, with AI-related demand driving proactive and reactive service growth. The stock trades at ~26.5x FY26E EPS, well below its 5-year average, suggesting undervaluation with a fair value estimate of $73.80 versus a ~$65 share price.','Seeking Alpha','2026-05-06T23:47:08','medium');
INSERT INTO "signals" VALUES(378,'EXPO','2026-05-05','8k','CYTOKINETICS INC  (CYTK)  (CIK 0001061983) 8-K','EXPO 2026-05-05','SEC EDGAR','2026-05-06T23:47:08','low');
