INSERT INTO "signals" VALUES(380,'FBIN','2026-05-04','news','Fortune Brands Innovations Declares Quarterly Dividend','DEERFIELD, Ill.--(BUSINESS WIRE)--Fortune Brands Innovations, Inc. (NYSE: FBIN or “Fortune Brands” or the “Company”), an industry-leading home, security and digital products company whose purpose is to elevate every life by transforming spaces into havens, today announced that its Board of Directors declared a quarterly cash dividend of $0.26 per common share. The dividend is payable on June 10, 2026, to stockholders of record as of the close of business on May 22, 2026. About Fortune Brands In.','Business Wire','2026-05-06T23:47:09','medium');
INSERT INTO "signals" VALUES(381,'FCN','2026-05-05','news','FTI Consulting Stock Declines 6.3% Since Q2 Earnings Miss','FCN misses Q2 EPS estimates despite revenue growth, sending shares down 6.3% as mixed segment performance and margin pressure weigh.','Zacks Investment Research','2026-05-06T23:47:10','medium');
INSERT INTO "signals" VALUES(382,'FCN','2026-05-05','news','FTI Consulting Appoints Retail & Consumer Products Transformation Expert Anand Raghuraman as Senior Managing Director','AMSTERDAM, May 05, 2026 (GLOBE NEWSWIRE) -- FTI Consulting, Inc. (NYSE: FCN) today announced the expansion of its Business Transformation practice with the appointment of Anand Raghuraman as a Senior Managing Director within the firm''s Corporate Finance segment.','GlobeNewsWire','2026-05-06T23:47:10','medium');
