INSERT INTO "signals" VALUES(384,'FLR','2026-05-04','news','Investing in X-energy Without the Pre-Revenue IPO Risk','X-energy (XE), the developer of the Xe-100 advanced small modular reactor (SMR) and XENITH microreactor, made its public market debut earlier this month. The company executed an upsized initial public offering that raised more than $1 billion.','ETF Trends','2026-05-06T23:47:12','medium');
INSERT INTO "signals" VALUES(385,'FLS','2026-05-05','news','Flowserve Prices Senior Notes Offering','DALLAS--(BUSINESS WIRE)--Flowserve Corporation (NYSE: FLS) ("Flowserve" or the "Company"), a leading provider of flow control products and services for the global infrastructure markets, today announced the pricing of a public offering of $500 million of its 5.700% senior notes due 2036. The offering is expected to close on May 12, 2026, subject to customary conditions. The notes will be general senior unsecured obligations of the Company and will rank equally in right of payment with the Compa.','Business Wire','2026-05-06T23:47:14','medium');
