INSERT INTO "signals" VALUES(682,'LZ','2026-05-06','news','LegalZoom Reports First Quarter Financial Results Ahead of Expectations; Raises Full-Year Revenue Outlook','Revenue of $206.8 million, up 13% year-over-year; reflecting continued growth in higher-value subscriptions and contributions from compliance product enhancements Subscription revenue of $130.2 million up 12% year-over- year, driven by growth in differentiated human-in-the-loop service offerings Net income of $1.1 million and net income margin of 1% Adjusted EBITDA of $36.5 million and Adjusted EBITDA margin of 18% Commitment to shareholder returns; completed $43.5 million of share repurchases in the quarter Ended the quarter with cash and cash equivalents of $183.2 million, delivered $47.3 million in cash from operating activities and $41.0 million in free cash flow with no debt outstanding as of March 31, 2026 MOUNTAIN VIEW, Calif., May 06, 2026 (GLOBE NEWSWIRE) -- LegalZoom (Nasdaq: LZ)','GlobeNewsWire','2026-05-06T23:47:56','medium');
