INSERT INTO "signals" VALUES(831,'MATX','2026-05-05','news','MATSON NEW VESSEL CONSTRUCTION PROGRAM MARKS TWO MILESTONES','PHILADELPHIA, May 5, 2026 /PRNewswire/ -- Matson, Inc. ("Matson"; NYSE: MATX) today marked two milestones in its fleet renewal program with the beginning of hull assembly on the second of three new LNG powered "Aloha Class" containerships designed for its Hawaii and China-Long Beach Express (CLX) services, and the start of construction on its third new vessel at Hanwha Philly Shipyard, Inc. (HSPI) in Pennsylvania. A small shipyard ceremony to mark the dock mounting of the first grand block assembly of the second new vessel was followed by the cutting of steel plates to initiate work to build the third vessel.','PRNewsWire','2026-05-06T23:48:04','medium');
