INSERT INTO "signals" VALUES(833,'MATX','2026-05-04','news','MATSON, INC. ANNOUNCES FIRST QUARTER 2026 RESULTS','1Q26 EPS of $1.85 versus $2.18 in 1Q25 1Q26 Net Income of $56.6 million versus $72.3 million in 1Q25 1Q26 Consolidated Operating Income of $61.4 million versus $82.1 million in 1Q25 1Q26 EBITDA of $113.3 million versus $131.7 million in 1Q25 Repurchased approximately 0.4 million shares in 1Q26 Raises full year outlook HONOLULU, May 4, 2026 /PRNewswire/ -- Matson, Inc. ("Matson" or the "Company") (NYSE: MATX), a leading U.S. carrier in the Pacific, today reported net income of $56.6 million, or $1.85 per diluted share, for the quarter ended March 31, 2026.  Net income for the quarter ended March 31, 2025 was $72.3 million, or $2.18 per diluted share.','PRNewsWire','2026-05-06T23:48:04','medium');
