INSERT INTO "signals" VALUES(934,'MSA','2026-05-04','news','MSA Safety Announces First Quarter 2026 Results','First Quarter 2026  Highlights Achieved quarterly net sales of $464 million, a 10% GAAP increase and a 3% organic increase year-over-year Generated GAAP operating income of $93 million, or 20.1% of sales, and adjusted operating income of $101 million, or 21.8% of sales Recorded GAAP net income of $71 million, or $1.83 per diluted share, and adjusted earnings of $77 million, or $1.99 per diluted share Returned a total of $71 million to shareholders via $50 million of share repurchases and $21 million of dividends; authorized a new $500 million share repurchase program Maintain a strong balance sheet and ample liquidity to support Accelerate strategy PITTSBURGH, May 4, 2026 /PRNewswire/ -- Global safety equipment and solutions provider MSA Safety Incorporated (NYSE: MSA) today reported finan','PRNewsWire','2026-05-06T23:48:21','medium');
INSERT INTO "signals" VALUES(935,'MSA','2026-05-04','news','MSA Safety Announces 56 Consecutive Years of Annual Dividend Increases','PITTSBURGH, May 4, 2026 /PRNewswire/ -- The Board of Directors of MSA Safety Incorporated (NYSE: MSA) today approved the company''s 56th consecutive annual dividend increase, raising the quarterly dividend from $0.53 per common share to $0.54 per common share. The change reflects a 2% increase in the quarterly dividend and a 2% increase in 2026 dividends per common share compared to 2025.','PRNewsWire','2026-05-06T23:48:21','medium');
