INSERT INTO "signals" VALUES(1454,'SAIC','2026-05-05','news','Building Homes for Heroes Announces Mortgage-Free Home Gifts for Two Injured Veterans','National Capitol Classic golf fundraiser at the historic Army Navy Country Club, co-hosted with SAIC and Amazon Web Services, raised funds to support these veterans and their families and expand Building Homes for Heroes'' impact nationwide WASHINGTON, May 5, 2026 /PRNewswire/ -- Building Homes for Heroes, joined by corporate partners Science Applications International Corp. (NASDAQ: SAIC) and Amazon Web Services, announced yesterday it will gift mortgage-free homes to U.S. Air Force Staff Sergeant, Gregory Walker and Army Specialist, Ryan Heard, two injured veterans whose service and sacrifice exemplify the very best of our armed forces. The home gifts will provide long-term stability for both veterans and their families as they continue their road to recovery.','PRNewsWire','2026-05-06T23:49:14','medium');
