INSERT INTO "signals" VALUES(1471,'SONO','2026-05-04','news','Sonos Reports Second Quarter Fiscal 2026 Results','SANTA BARBARA, Calif.--(BUSINESS WIRE)---- $SONO--Sonos, Inc. (Nasdaq: SONO) today reported Second Quarter Fiscal 2026 results. “The first half of Fiscal 2026 marks an important turning point for Sonos as we return to growth and change the trajectory of the business,” said Tom Conrad, Chief Executive Officer of Sonos. “The progress we''re seeing comes from coordinated execution across the areas that matter most: better products, a stronger software experience, more effective marketing, and continued expan.','Business Wire','2026-05-06T23:49:20','medium');
