INSERT INTO "signals" VALUES(1482,'SR','2026-05-06','news','Spire reports FY26 second quarter results','ST. LOUIS, May 6, 2026 /PRNewswire/ -- Spire Inc. (NYSE: SR) today reported results for its fiscal 2026 second quarter ended March 31. Highlights include: Completed acquisition of the Piedmont Natural Gas Tennessee business on March 31, 2026 Following quarter-end, completed sale of Spire Marketing; announced agreements to sell Spire Storage and Spire Mississippi Second quarter net income of $217.6 million ($3.51 per diluted share) compared to $189.3 million ($3.17 per share) a year ago Second quarter adjusted earnings* from continuing operations of $223.7 million ($3.76 per share) compared to $189.3 million ($3.17 per share) a year ago Second quarter net income and adjusted earnings reflect the classification of Spire Marketing and Spire Storage as discontinued operations, with prior-perio','PRNewsWire','2026-05-06T23:49:26','medium');
