INSERT INTO "signals" VALUES(3093,'AAON','2026-05-07','news','Aaon (AAON) Surpasses Q1 Earnings and Revenue Estimates','Aaon (AAON) came out with quarterly earnings of $0.48 per share, beating the Zacks Consensus Estimate of $0.31 per share. This compares to earnings of $0.37 per share a year ago.','Zacks Investment Research','2026-05-07T20:00:05','medium');
INSERT INTO "signals" VALUES(3094,'AAON','2026-05-07','news','AAON Reports First Quarter 2026 Results with Record Sales and Backlog, Robust Earnings Growth, and Raises Full-Year Guidance','First Quarter 2026 Results (All comparisons are year-over-year, unless otherwise noted) Delivered record sales and accelerated earnings growth on strong demand and expanding production throughput Net sales grew 54.3% to a record $496.9 million Operating margins reflected early benefits from improving utilization, with margin improvement expected to build as capacity absorption improves GAAP diluted EPS increased 37.1% to $0.48 reflecting strong earnings growth on higher volume Total backlog increased 107.4% to a record $2.1 billion, driven by continued strength from the data center market  Raises 2026 Outlook 2026 outlook now reflects revenue growth of 40%-45%% and gross margins of approximately 27-28%, supported by record backlog, expanded capacity, and improving operational execution TUL','PRNewsWire','2026-05-07T20:00:05','medium');
