INSERT INTO "signals" VALUES(3097,'CNR','2026-05-07','news','Core Natural Resources (CNR) Surpasses Q1 Earnings and Revenue Estimates','Core Natural Resources (CNR) came out with quarterly earnings of $0.41 per share, beating the Zacks Consensus Estimate of a loss of $0.01 per share. This compares to a loss of $1.38 per share a year ago.','Zacks Investment Research','2026-05-07T20:00:16','medium');
INSERT INTO "signals" VALUES(3098,'CNR','2026-05-07','news','Core Natural Resources Reports First Quarter 2026 Results','Reports net income of $21.0 million and adjusted EBITDA 1 of $179.9 million Delivers excellent operating performances at Leer South and West Elk Generates net cash provided by operating activities of $119.4 million and free cash flow 1 of $55.5 million  Returns $47.0 million to stockholders, bringing the total returned to stockholders since Q1 2025 to $292.1 million CANONSBURG, Pa., May 7, 2026 /PRNewswire/ -- Today, Core Natural Resources, Inc. (NYSE: CNR) ("Core" or the "company") reported net income of $21.0 million, or $0.41 per diluted share, in the first quarter of 2026.','PRNewsWire','2026-05-07T20:00:16','medium');
