INSERT INTO "signals" VALUES(3106,'GOGO','2026-05-07','news','Gogo (GOGO) Lags Q1 Earnings and Revenue Estimates','Gogo (GOGO) came out with quarterly earnings of $0.07 per share, missing the Zacks Consensus Estimate of $0.09 per share. This compares to earnings of $0.18 per share a year ago.','Zacks Investment Research','2026-05-07T20:00:31','medium');
