INSERT INTO "signals" VALUES(3116,'OLLI','2026-05-07','news','Artisan Small Cap Fund Q1 2026 Portfolio Activity','During the quarter, we initiated new Garden positions in Onto Innovation, Baldwin Group and Freshpet. In addition to Compass, we added to our positions in Ollie''s Bargain Outlet and Flowserve during the quarter. We ended our investment campaigns in Penumbra, JBT Marel and Parsons during the quarter.','Seeking Alpha','2026-05-07T20:00:52','medium');
