INSERT INTO "signals" VALUES(3220,'ROCK','2026-05-07','news','Gibraltar Reports First Quarter 2026 Results','BUFFALO, N.Y.--(BUSINESS WIRE)---- $ROCK #ROCK--Gibraltar Industries, Inc. (Nasdaq: ROCK), a leading manufacturer and provider of products and services for the residential, agtech, and infrastructure markets, today reported its financial results for the three-month period ended March 31, 2026. As a reminder, on June 30, 2025, Gibraltar announced that it has reclassified its Renewables business as discontinued operations to focus its asset portfolio and resources on its building products and structures business.','Business Wire','2026-05-07T20:00:59','medium');
