INSERT INTO "signals" VALUES(3231,'SGI','2026-05-07','news','Somnigroup Announces Second Quarter Cash Dividend','DALLAS, May 7, 2026 /PRNewswire/ -- Somnigroup International Inc. (NYSE: SGI, "Company" or "Somnigroup") today announced that its Board of Directors has declared a second quarter cash dividend on its common stock of $0.17 per share. The dividend is payable on June 4, 2026, to shareholders of record as of May 21, 2026.','PRNewsWire','2026-05-07T20:01:00','medium');
INSERT INTO "signals" VALUES(3232,'SGI','2026-05-07','news','Somnigroup International Inc. Reports First Quarter 2026 Results','- First Quarter 2026 Net Sales Increased 12% to $1.8 Billion - EPS Growth of 388% and Adjusted EPS(1) Growth of 20% - Record First Quarter Cash Flows from Operations of $246 Million DALLAS, May 7, 2026 /PRNewswire/ -- Somnigroup International Inc. (NYSE: SGI, "Company") announced financial results for the first quarter ended March 31, 2026 and reaffirmed financial guidance for the full year 2026. FIRST  QUARTER 2026 FINANCIAL SUMMARY Total net sales increased 12.3% to $1,801.5 million as compared to $1,604.7 million in the first quarter of 2025, primarily driven by the inclusion of Mattress Firm sales for a full quarter as compared to the first quarter of 2025, which included Mattress Firm for the period of February 5, 2025 through March 31, 2025.','PRNewsWire','2026-05-07T20:01:00','medium');
